let incode,session,container=document.getElementById("incode-container");function notifyCompletion(n){const e=new CustomEvent("incodeCompleted",{detail:n});window.dispatchEvent(e)}async function init(){const n=await fetch("https://testint-744443929525.northamerica-south1.run.app/create-session",{method:"POST"});session=await n.json(),incode=await window.OnBoarding.create({apiURL:"https://demo-api.incodesmile.com/0"}),await sendGeo()}async function sendGeo(){await incode.sendGeolocation({token:session.token}).catch(console.error),renderID()}function renderID(){incode.renderCaptureId(container,{session:session,onSuccess:runIdValidation,onError:console.error})}async function runIdValidation(){try{await incode.processId({token:incodeSession.token});renderFace()}catch(n){console.log(n)}}function renderFace(){incode.renderCaptureFace(container,{session:session,onSuccess:doFaceMatch,onError:console.error})}async function doFaceMatch(){await incode.processFace({token:session.token}),await incode.finishOnboarding({token:session.token}),notifyCompletion({token:session.token,status:"completed"})}"loading"===document.readyState?document.addEventListener("DOMContentLoaded",()=>{container=document.getElementById("incode-container"),init()}):init();